logger = logging.getLogger(__name__)
iri_regex = re.compile(r'https?://[^/]+/(?P<id>\w{5})/?')

def get_object_by_url[T: Model](url: str, model: type[T]) -> T | None:
    if not (match := iri_regex.match(url)):
        log_message(f"received invalid {model.__name__} {url=}. ", skip_session=True)
        return None
    try:
        return model.objects.get(guids___id=match['id'])
    except model.DoesNotExist:
        log_message(f"Could not find {model.__name__} with id={match['id']}", skip_session=True)
        return None

@app.task(max_retries=5, name='osf.tasks.log_gv_addon', default_retry_delay=10)
def log_gv_addon(node_url: str, action: str, user_url: str, addon: str):
    from osf.models import NodeLog, OSFUser, Node

    PERMITTED_GV_ACTIONS = frozenset({
        NodeLog.ADDON_ADDED,
        NodeLog.ADDON_REMOVED
    })
    if action not in PERMITTED_GV_ACTIONS:
        log_message(f"{action} is not permitted to be logged from GV", skip_session=True)
        return

    node = get_object_by_url(node_url, Node)
    user = get_object_by_url(user_url, OSFUser)
    if not node or not user:
        return

    node.add_log(
        action=action,
        auth=user,
        params={
            'node': node._id,
            'project': node.parent_id,
            'addon': addon
        }
    )
    if node.is_public:
        node.update_search()

import os
import itertools

from furl import furl
import requests

from framework.exceptions import HTTPError


class BaseClient:

    @property
    def _auth(self):
        return None

    @property
    def _default_headers(self):
        return {}

    @property
    def _default_params(self):
        return {}

    def _make_request(self, method, url, **kwargs):
        expects = kwargs.pop('expects', None)
        throws = kwargs.pop('throws', None)

        kwargs['headers'] = self._build_defaults(self._default_headers, **kwargs.get('headers', {}))
        kwargs['params'] = self._build_defaults(self._default_params, **kwargs.get('params', {}))

        response = requests.request(method, url, auth=self._auth, **kwargs)
        if expects and response.status_code not in expects:
            raise throws if throws else HTTPError(response.status_code, message=response.content)

        return response

    def _build_defaults(self, defaults, **kwargs):
        defaults.update(kwargs)
        return {
            key: value
            for key, value in defaults.items()
            if value is not None
        }

    def _build_url(self, base, *segments):
        # NOTE: furl encoding to be verified later
        url = furl(base)
        segments = [segment for segment in [str(segment).strip('/') for segment in itertools.chain(url.path.segments, segments)] if segment]
        url.set(path=os.path.join(*segments))
        return url.url

from .pagination import PAGE_VAR, Pagination

TAB_VAR = "tab"


class ObjectList:
    pagination_class = Pagination
    base_ordering = ()
    sorting_tabs = {}

    def __init__(self, request, model, queryset, list_per_page):
        self.model = model
        self.opts = model._meta
        self.queryset = queryset
        self.list_per_page = list_per_page
        self.params = dict(request.GET.dict())
        self.current_tab = self.params.get(TAB_VAR, None)
        if self.opts.ordering:
            self.base_ordering = list(self.opts.ordering)
        if PAGE_VAR in self.params:
            del self.params[PAGE_VAR]
        self.result_objects = self.get_objects(request, queryset)

    def __iter__(self):
        return iter(self.result_objects)

    def tab_sort(self, queryset):
        result_queryset = queryset
        if self.current_tab:
            sort_value = self.sorting_tabs[self.current_tab]
            result_queryset = result_queryset.order_by(*sort_value, *self.base_ordering)
        else:
            for tab_name, tab_order in self.sorting_tabs.items():
                if list(tab_order) == self.base_ordering:
                    self.current_tab = tab_name
                    break

        return result_queryset

    def paginate(self, request, queryset):
        pagination = self.pagination_class(
            request,
            self.model,
            queryset,
            self.list_per_page,
        )
        self.pagination = pagination
        return pagination.get_objects()

    def get_objects(self, request, queryset):
        tab_result = self.tab_sort(queryset)
        return self.paginate(request, tab_result)

